txt = ""
if os.path.exists("ipopt.out"):
    with open("ipopt.out", "r", encoding="utf-8", errors="replace") as f:
        txt = f.read()

def grab_int(pat):
    m = re.search(pat, txt)
    return int(m.group(1)) if m else None

def grab_float(pat):
    m = re.search(pat, txt)
    return float(m.group(1)) if m else None

